import{c as a,S as t,j as s,m as o}from"./chunks/framework.CDB06nwH.js";const u=JSON.parse('{"title":"News","description":"","frontmatter":{},"headers":[],"relativePath":"news.md","filePath":"news.md","lastUpdated":null}'),r={name:"news.md"};function n(i,e,l,d,p,h){return t(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="News" tabindex="-1">News <a class="header-anchor" href="#News" aria-label="Permalink to &quot;News {#News}&quot;">​</a></h1><p>Release notes for BVDOutbreakSize. Major versions of the report are kept as <a href="https://github.com/epiforecasts/BVDOutbreakSize/releases" target="_blank" rel="noreferrer">GitHub Releases</a>; each push to <code>main</code> also republishes the rendered analysis and the <code>output/</code> artifacts.</p><h2 id="v1.0.0" tabindex="-1">v1.0.0 <a class="header-anchor" href="#v1.0.0" aria-label="Permalink to &quot;v1.0.0 {#v1.0.0}&quot;">​</a></h2><p>First release. A joint Bayesian re-analysis of the McCabe et al. report that fits all data streams together in a single Turing model over the latent cumulative case count.</p><ul><li><p>Conditions on the exported cases and DRC deaths the report uses, plus reported DRC cases (with an ascertainment component) and deaths among exported cases.</p></li><li><p>Adds a no-onward-transmission projected-deaths counterfactual, a one-week-ahead forecast of newly reported cases, deaths and exports, and an onset-to-death delay sensitivity analysis.</p></li><li><p>Replaces the deaths-convolution and small-growth-rate exports closed-form approximations with their exact forms.</p></li><li><p>Maths-first analysis page with code folded behind dropdowns and a diagram of the model build-up.</p></li><li><p>Compares against a joint reimplementation of the report&#39;s approach and its original published estimates.</p></li></ul>',5)])])}const m=a(r,[["render",n]]);export{u as __pageData,m as default};
